"use server"

import { prisma } from "@/lib/prisma"
import { revalidatePath } from "next/cache"

export async function uploadAuditRecords(records: any[]) {
  try {
    // Basic validation
    if (!records || !Array.isArray(records)) {
      throw new Error("Invalid records format")
    }

    // Convert string amounts and capacities to numbers
    const formattedRecords = records.map(record => {
      // Handle Date formats
      let date = new Date()
      if (record.date) {
         const parsed = new Date(record.date)
         if (!isNaN(parsed.getTime())) {
           date = parsed
         }
      }

      return {
        customer: String(record.customer || "Unknown"),
        mobile: record.mobile ? String(record.mobile) : null,
        date: date,
        capacity: Number(record.capacity) || 0,
        amount: Number(record.amount) || 0,
        salesperson: String(record.salesperson || "Unknown")
      }
    })

    // Batch insert using prisma
    await prisma.enterpriseAuditRecord.createMany({
      data: formattedRecords,
      skipDuplicates: true // Just in case
    })

    revalidatePath("/dashboard/analytics")
    return { success: true, message: `Successfully uploaded ${formattedRecords.length} records.` }
  } catch (error: any) {
    console.error("Upload error:", error)
    return { success: false, message: error.message || "Failed to upload records" }
  }
}

export async function getAuditRecords() {
    return await prisma.enterpriseAuditRecord.findMany({
        orderBy: { date: 'desc' }
    })
}

"use server"

import { prisma } from "@/lib/prisma"
import { revalidatePath } from "next/cache"
import { z } from "zod"
import { getSessionOrThrow, requireDealAccess, requireLeadAccess, hasRole, getSubtreeAgentIds, requireRole } from "@/lib/authorization"
import { defineAbilityFor } from "@/lib/authz/ability"
import { accessibleBy } from "@casl/prisma"

const DealSchema = z.object({
  leadId: z.string().min(1),
  name: z.string().optional().or(z.literal("")),
  dealValue: z.coerce.number().positive("Deal value must be positive"),
  originalPrice: z.coerce.number().optional().or(z.literal("")),
  discount: z.coerce.number().optional().or(z.literal("")),
  expectedCloseDate: z.string().optional().or(z.literal("")),
  category: z.string().optional().or(z.literal("")),
  notes: z.string().optional().or(z.literal("")),
})

// ── COMMISSION ENGINE: Graph Traversal ──
async function getActiveRate(agentId: string, baseRate: number, commissionType: string, newDealValue: number) {
  if (commissionType !== "TIERED") return baseRate

  const startOfMonth = new Date()
  startOfMonth.setDate(1)
  startOfMonth.setHours(0, 0, 0, 0)

  const volumeAgg = await prisma.deal.aggregate({
    where: {
      status: "CLOSED_WON",
      closedAt: { gte: startOfMonth },
      commissions: { some: { agentId } }
    },
    _sum: { dealValue: true }
  })

  const currentVolume = (Number(volumeAgg._sum.dealValue) || 0) + newDealValue

  const tiers = await prisma.commissionTier.findMany({
    where: { agentId },
    orderBy: { volumeThreshold: "desc" }
  })

  for (const tier of tiers) {
    if (currentVolume >= Number(tier.volumeThreshold)) return Number(tier.rate)
  }

  return baseRate
}

async function calculateCommissions(dealId: string) {
  const deal = await prisma.deal.findUnique({
    where: { id: dealId },
    include: { lead: { include: { owner: true } } },
  })

  if (!deal || !deal.lead) throw new Error("Deal or Lead not found")

  const commissions: { agentId: string; role: string; commissionType: string; rate: number; amount: number }[] = []
  const visited = new Set<string>() // Cycle prevention

  // 1. OWNER commission — the agent who submitted the lead
  const owner = deal.lead.owner
  const ownerRate = await getActiveRate(owner.id, Number(owner.commissionRate), owner.commissionType, Number(deal.dealValue))

  commissions.push({
    agentId: owner.id,
    role: "OWNER",
    commissionType: owner.commissionType,
    rate: ownerRate,
    amount: owner.commissionType === "FIXED_AMOUNT" 
      ? ownerRate 
      : (Number(deal.dealValue) * ownerRate) / 100,
  })
  visited.add(owner.id)

  // 2. Walk UP the hierarchy for OVERRIDE commissions
  let currentAgentId = owner.parentId

  while (currentAgentId) {
    if (visited.has(currentAgentId)) break // Cycle guard

    const parentAgent = await prisma.agent.findUnique({
      where: { id: currentAgentId },
    })

    if (!parentAgent) break

    visited.add(parentAgent.id)

    const parentRate = await getActiveRate(parentAgent.id, Number(parentAgent.commissionRate), parentAgent.commissionType, Number(deal.dealValue))

    commissions.push({
      agentId: parentAgent.id,
      role: "OVERRIDE",
      commissionType: parentAgent.commissionType,
      rate: parentRate,
      amount: parentAgent.commissionType === "FIXED_AMOUNT"
        ? parentRate
        : (Number(deal.dealValue) * parentRate) / 100,
    })

    currentAgentId = parentAgent.parentId
  }

  // 3. Persist all commissions in a transaction
  await prisma.$transaction(
    commissions.map((c) =>
      prisma.commission.upsert({
        where: {
          dealId_agentId_role: {
            dealId,
            agentId: c.agentId,
            role: c.role,
          },
        },
        update: {
          commissionType: c.commissionType,
          rate: c.rate,
          amount: c.amount,
        },
        create: {
          dealId,
          agentId: c.agentId,
          role: c.role,
          commissionType: c.commissionType,
          rate: c.rate,
          amount: c.amount,
          status: "PENDING",
        },
      })
    )
  )

  return commissions
}

export async function getDeals() {
  const user = await getSessionOrThrow()
  const ability = await defineAbilityFor(user)

  return prisma.deal.findMany({
    where: accessibleBy(ability).Deal,
    include: {
      lead: {
        select: { name: true, owner: { select: { name: true, agentCode: true } } },
      },
      _count: { select: { commissions: true } },
    },
    orderBy: { createdAt: "desc" },
  })
}

export async function getDealById(id: string) {
  const user = await getSessionOrThrow()
  await requireDealAccess(user, id, "OWNER", "ASSIGNED", "ANCESTOR")

  const deal = await prisma.deal.findUnique({
    where: { id },
    include: {
      lead: {
        include: {
          owner: true,
          contacts: { where: { isPrimary: true } },
          assignments: true,
        },
      },
      commissions: {
        include: {
          agent: { select: { id: true, name: true, agentCode: true, type: true } },
          payout: true,
        },
        orderBy: { role: "asc" },
      },
    },
  })

  if (!deal) return null

  return deal
}

export async function createDeal(formData: FormData) {
  const user = await getSessionOrThrow()
  const raw = Object.fromEntries(formData)
  const parsed = DealSchema.safeParse(raw)

  if (!parsed.success) {
    return { error: parsed.error.flatten().fieldErrors }
  }

  const { leadId, dealValue, category, notes, name, originalPrice, discount, expectedCloseDate } = parsed.data

  await requireLeadAccess(user, leadId, "OWNER", "ASSIGNED", "ANCESTOR")

  let dealName = name
  if (!dealName) {
    const lead = await prisma.lead.findUnique({ where: { id: leadId }, select: { name: true } })
    if (lead) {
      dealName = `${lead.name}'s Project`
    }
  }

  const deal = await (prisma.deal as any).create({
    data: {
      leadId,
      name: dealName || "New Project",
      dealValue,
      originalPrice: originalPrice ? Number(originalPrice) : null,
      discount: discount ? Number(discount) : 0,
      expectedCloseDate: expectedCloseDate ? new Date(expectedCloseDate) : null,
      category: category || null,
      notes: notes || null,
      status: "NEW_QUALIFIED",
    },
  })

  revalidatePath("/dashboard/deals")
  revalidatePath(`/dashboard/leads/${leadId}`)
  return { success: true, dealId: deal.id }
}

export async function updateDealDocuments(dealId: string, docs: { quotationUrl?: string; proposalUrl?: string; agreementUrl?: string; surveyReportUrl?: string }) {
  const user = await getSessionOrThrow()
  await requireDealAccess(user, dealId, "OWNER", "ASSIGNED", "ANCESTOR")

  await (prisma.deal as any).update({
    where: { id: dealId },
    data: docs,
  })

  revalidatePath(`/dashboard/deals/${dealId}`)
  return { success: true }
}

export async function updateDealStatus(dealId: string, status: string) {
  const user = await getSessionOrThrow()
  await requireDealAccess(user, dealId, "OWNER", "ASSIGNED", "ANCESTOR")

  const deal = await prisma.deal.findUnique({ where: { id: dealId } })
  if (!deal) return { error: "Deal not found" }

  const updateData: { status: string; closedAt?: Date } = { status }

  if (status === "CLOSED_WON") {
    updateData.closedAt = new Date()

    // Update deal first
    await prisma.deal.update({ where: { id: dealId }, data: updateData })

    // Trigger commission engine
    const commissions = await calculateCommissions(dealId)

    // Also update the lead status
    await prisma.lead.update({
      where: { id: deal.leadId },
      data: { status: "CLOSED_WON" },
    })

    revalidatePath("/dashboard/deals")
    revalidatePath(`/dashboard/deals/${dealId}`)
    revalidatePath("/dashboard/commissions")
    return { success: true, commissionsGenerated: commissions.length }
  }

  if (status === "CLOSED_LOST") {
    updateData.closedAt = new Date()
    await prisma.deal.update({ where: { id: dealId }, data: updateData })
    await prisma.lead.update({ where: { id: deal.leadId }, data: { status: "CLOSED_LOST" } })
  } else {
    await prisma.deal.update({ where: { id: dealId }, data: updateData })
  }

  revalidatePath("/dashboard/deals")
  revalidatePath(`/dashboard/deals/${dealId}`)
  return { success: true }
}

export async function approveCommission(commissionId: string) {
  const user = await getSessionOrThrow()
  requireRole(user, "ADMIN")

  await prisma.commission.update({
    where: { id: commissionId },
    data: { status: "APPROVED" },
  })
  revalidatePath("/dashboard/commissions")
  return { success: true }
}

export async function disputeCommission(commissionId: string, note: string) {
  const user = await getSessionOrThrow()
  requireRole(user, "ADMIN")

  await prisma.commission.update({
    where: { id: commissionId },
    data: { status: "DISPUTED", disputeNote: note },
  })
  revalidatePath("/dashboard/commissions")
  return { success: true }
}

export async function recordPayout(commissionId: string, formData: FormData) {
  const user = await getSessionOrThrow()
  requireRole(user, "ADMIN")

  const method = formData.get("method") as string
  const reference = formData.get("reference") as string
  const paidBy = formData.get("paidBy") as string

  const commission = await prisma.commission.findUnique({ where: { id: commissionId } })
  if (!commission) return { error: "Commission not found" }

  await prisma.$transaction([
    prisma.payout.create({
      data: {
        commissionId,
        agentId: commission.agentId,
        amount: Number(commission.amount),
        method: method || null,
        reference: reference || null,
        paidBy: paidBy || user.name || "admin",
      },
    }),
    prisma.commission.update({
      where: { id: commissionId },
      data: { status: "PAID" },
    }),
  ])

  revalidatePath("/dashboard/commissions")
  return { success: true }
}

export async function getCommissions(filters?: { agentId?: string; status?: string }) {
  const user = await getSessionOrThrow()
  const where: { agentId?: string; status?: string } = {}

  if (!hasRole(user, "ADMIN")) {
    // Non-admins can only see their own commissions
    where.agentId = user.agentId
  } else if (filters?.agentId) {
    where.agentId = filters.agentId
  }

  if (filters?.status) where.status = filters.status

  return prisma.commission.findMany({
    where,
    include: {
      agent: { select: { id: true, name: true, agentCode: true } },
      deal: {
        select: {
          id: true,
          dealValue: true,
          status: true,
          lead: { select: { name: true } },
        },
      },
      payout: true,
    },
    orderBy: { createdAt: "desc" },
  })
}

"use server"

import { prisma } from "@/lib/prisma"
import { revalidatePath } from "next/cache"
import { z } from "zod"
import { getSessionOrThrow, requireLeadAccess, hasRole, getSubtreeAgentIds } from "@/lib/authorization"

const LeadSchema = z.object({
  name: z.string().min(1, "Name is required"),
  email: z.string().email().optional().or(z.literal("")),
  location: z.string().min(1, "Location is required"),
  notes: z.string().optional().or(z.literal("")),
  sourceType: z.enum(["AGENT", "SALESPERSON", "DIRECT"]),
  ownerId: z.string().min(1, "Owner is required"),
  phoneNumber: z.string().min(10, "Phone number must be at least 10 digits"),
  customerType: z.enum(["RESIDENTIAL", "COMMERCIAL"]).optional().or(z.literal("")),
})

// ── Duplicate Detection ──
export async function checkDuplicatePhone(phone: string) {
  const existing = await prisma.leadContact.findUnique({
    where: { phoneNumber: phone },
    include: {
      lead: {
        select: { id: true, name: true, owner: { select: { name: true, agentCode: true } } },
      },
    },
  })

  if (existing) {
    return {
      isDuplicate: true,
      existingLead: existing.lead,
    }
  }
  return { isDuplicate: false }
}

export async function getLeads(filters?: { agentId?: string; status?: string }) {
  const user = await getSessionOrThrow()
  const where: any = {}

  if (!hasRole(user, "ADMIN")) {
    // Non-admins only see leads in their subtree or explicitly assigned
    const agentId = user.agentId
    if (agentId) {
      const subtreeIds = await getSubtreeAgentIds(agentId)
      where.OR = [
        { ownerId: { in: subtreeIds } },
        { assignments: { some: { agentId } } }
      ]
    } else {
      // No agent linked, can only see explicitly assigned leads if any (should be none)
      where.id = "none" 
    }
  } else if (filters?.agentId) {
    // Admin filtering by a specific agent
    where.OR = [
      { ownerId: filters.agentId },
      { assignments: { some: { agentId: filters.agentId } } }
    ]
  }

  if (filters?.status) where.status = filters.status

  return prisma.lead.findMany({
    where,
    include: {
      owner: { select: { name: true, agentCode: true } },
      contacts: { select: { phoneNumber: true, isPrimary: true, label: true } },
      _count: { select: { deals: true } },
      assignments: { select: { agentId: true } }
    },
    orderBy: { createdAt: "desc" },
  })
}

export async function getLeadById(id: string) {
  const user = await getSessionOrThrow()
  await requireLeadAccess(user, id, "OWNER", "ASSIGNED", "ANCESTOR")

  const lead = await prisma.lead.findUnique({
    where: { id },
    include: {
      owner: true,
      contacts: true,
      assignments: { include: { agent: { select: { name: true, agentCode: true } } } },
      deals: {
        include: {
          commissions: { include: { agent: { select: { name: true } } } },
        },
      },
      activities: { orderBy: { createdAt: "desc" }, take: 20 },
    },
  })

  if (!lead) return null

  return lead
}

export async function createLead(formData: FormData) {
  const user = await getSessionOrThrow()
  const raw = Object.fromEntries(formData)
  const parsed = LeadSchema.safeParse(raw)

  if (!parsed.success) {
    return { error: parsed.error.flatten().fieldErrors }
  }

  const { name, email, location, notes, sourceType, ownerId, phoneNumber, customerType } = parsed.data

  // Check duplicate phone
  const dupCheck = await checkDuplicatePhone(phoneNumber)
  if (dupCheck.isDuplicate) {
    return {
      error: {
        phoneNumber: [`This phone already belongs to lead "${dupCheck.existingLead!.name}" (owned by ${dupCheck.existingLead!.owner.name})`],
      },
    }
  }

  const lead = await prisma.lead.create({
    data: {
      name,
      email: email || null,
      location,
      notes: notes || null,
      customerType: customerType || null,
      sourceType,
      ownerId,
      contacts: {
        create: [{ phoneNumber, isPrimary: true, label: "Primary" }],
      },
    },
  })

  // ── Automatic Assignment up the Hierarchy ──
  // If the owner has parents, assign the lead to them automatically
  let currentAgent = await prisma.agent.findUnique({
    where: { id: ownerId },
    select: { parentId: true }
  })

  while (currentAgent?.parentId) {
    await prisma.leadAssignment.create({
      data: {
        leadId: lead.id,
        agentId: currentAgent.parentId,
        assignedBy: ownerId, // Assigned by the originator
      }
    })

    // Move up
    currentAgent = await prisma.agent.findUnique({
      where: { id: currentAgent.parentId },
      select: { parentId: true }
    })
  }

  // Log activity
  await prisma.leadActivity.create({
    data: {
      leadId: lead.id,
      type: "CREATED",
      newValue: `Lead submitted via ${sourceType}. Auto-assigned to parent managers.`,
      byUserId: ownerId,
    },
  })

  revalidatePath("/dashboard/leads")
  return { success: true, leadId: lead.id }
}

export async function updateLeadStatus(leadId: string, status: string, userId: string) {
  const user = await getSessionOrThrow()
  await requireLeadAccess(user, leadId, "OWNER", "ASSIGNED", "ANCESTOR")
  const lead = await prisma.lead.findUnique({ where: { id: leadId } })
  if (!lead) return { error: "Lead not found" }

  const oldStatus = lead.status

  await prisma.lead.update({
    where: { id: leadId },
    data: { status },
  })

  await prisma.leadActivity.create({
    data: {
      leadId,
      type: "STATUS_CHANGE",
      oldValue: oldStatus,
      newValue: status,
      byUserId: userId,
    },
  })

  revalidatePath(`/dashboard/leads/${leadId}`)
  revalidatePath("/dashboard/leads")
  return { success: true }
}

export async function addLeadContact(leadId: string, formData: FormData) {
  const user = await getSessionOrThrow()
  await requireLeadAccess(user, leadId, "OWNER", "ASSIGNED", "ANCESTOR")
  const phoneNumber = formData.get("phoneNumber") as string
  const label = formData.get("label") as string

  if (!phoneNumber || phoneNumber.length < 10) {
    return { error: "Valid phone number required" }
  }

  const dupCheck = await checkDuplicatePhone(phoneNumber)
  if (dupCheck.isDuplicate) {
    return { error: `Phone already belongs to lead "${dupCheck.existingLead!.name}"` }
  }

  await prisma.leadContact.create({
    data: { leadId, phoneNumber, label: label || null },
  })

  revalidatePath(`/dashboard/leads/${leadId}`)
  return { success: true }
}

export async function assignLead(leadId: string, agentId: string, assignedBy: string) {
  const user = await getSessionOrThrow()
  await requireLeadAccess(user, leadId, "OWNER", "ANCESTOR") // Only owners and ancestors can assign
  await prisma.leadAssignment.create({
    data: { leadId, agentId, assignedBy },
  })

  await prisma.leadActivity.create({
    data: {
      leadId,
      type: "ASSIGNED",
      newValue: agentId,
      byUserId: assignedBy,
    },
  })

  revalidatePath(`/dashboard/leads/${leadId}`)
  return { success: true }
}

"use server"

import { prisma } from "@/lib/prisma"
import { z } from "zod"
import { getSessionOrThrow, requireRole } from "@/lib/authorization"
import { revalidatePath } from "next/cache"
import bcrypt from "bcryptjs"
import { randomBytes } from "crypto"

// ─────────────────────────────────────────────────────────────────
// INVITE TOKEN ACTIONS
// ─────────────────────────────────────────────────────────────────

const GenerateInviteSchema = z.object({
  roleForInvitee: z.enum(["SALESPERSON", "SALES_AGENT", "SUB_SALES_AGENT"]),
  commissionRate: z.coerce.number().min(0).max(100).default(5),
  expiresInHours: z.coerce.number().min(1).max(168).default(48), // max 1 week
})

export async function generateInviteToken(formData: FormData) {
  const user = await getSessionOrThrow()
  // Allow ADMIN and SALESPERSON to generate invite links
  if (user.role !== "ADMIN" && user.role !== "SALESPERSON") {
    return { error: "Not authorized to generate invite links" }
  }

  const raw = Object.fromEntries(formData)
  const parsed = GenerateInviteSchema.safeParse(raw)
  if (!parsed.success) {
    return { error: "Invalid input" }
  }

  const { roleForInvitee, commissionRate, expiresInHours } = parsed.data

  const token = randomBytes(20).toString("hex")
  const expiresAt = new Date(Date.now() + expiresInHours * 60 * 60 * 1000)

  await (prisma as any).inviteToken.create({
    data: {
      token,
      createdByUserId: user.id,
      createdByAgentId: user.agentId ?? null,
      roleForInvitee,
      commissionRate,
      expiresAt,
    },
  })

  return { success: true, token }
}

export async function validateInviteToken(token: string) {
  const record = await (prisma as any).inviteToken.findUnique({
    where: { token },
    include: {
      application: { select: { id: true } },
    },
  })

  if (!record) return { valid: false, reason: "not_found" }
  if (record.usedAt) return { valid: false, reason: "used", data: record }
  if (new Date() > new Date(record.expiresAt)) return { valid: false, reason: "expired", data: record }

  // Fetch creator info for display
  let creatorName: string | null = null
  if (record.createdByAgentId) {
    const agent = await prisma.agent.findUnique({
      where: { id: record.createdByAgentId },
      select: { name: true },
    })
    creatorName = agent?.name ?? null
  }

  return {
    valid: true,
    data: {
      id: record.id,
      token: record.token,
      roleForInvitee: record.roleForInvitee as string,
      commissionRate: Number(record.commissionRate),
      expiresAt: record.expiresAt as Date,
      creatorName,
    },
  }
}

export async function getMyInviteTokens() {
  const user = await getSessionOrThrow()
  if (user.role !== "ADMIN" && user.role !== "SALESPERSON") {
    return []
  }

  return (prisma as any).inviteToken.findMany({
    where: { createdByUserId: user.id },
    include: { application: { select: { id: true, name: true, status: true } } },
    orderBy: { createdAt: "desc" },
    take: 20,
  })
}

// ─────────────────────────────────────────────────────────────────
// RECRUITMENT REQUEST ACTIONS
// ─────────────────────────────────────────────────────────────────

const ApplySchema = z.object({
  name: z.string().min(1, "Name is required"),
  email: z.string().email("Invalid email"),
  phone: z.string().min(10, "Phone number is too short"),
  location: z.string().optional(),
  requestedRole: z.enum(["SALESPERSON", "SUB_SALES_AGENT", "SALES_AGENT"]),
  referrerCode: z.string().optional(),
  notes: z.string().optional(),
  inviteToken: z.string().optional(),
}).superRefine((data, ctx) => {
  if (
    (data.requestedRole === "SALES_AGENT" || data.requestedRole === "SUB_SALES_AGENT") &&
    !data.referrerCode &&
    !data.inviteToken
  ) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "Referrer Code (Parent) is required for Sales Agents and Sub Sales Agents",
      path: ["referrerCode"],
    })
  }
})

export async function submitApplication(formData: FormData) {
  const raw = Object.fromEntries(formData)
  const parsed = ApplySchema.safeParse(raw)

  if (!parsed.success) {
    return { error: parsed.error.flatten().fieldErrors }
  }

  const { name, email, phone, location, requestedRole, referrerCode, notes, inviteToken } = parsed.data

  let referrerId = null
  let inviteTokenId: string | null = null

  // Validate invite token if provided
  if (inviteToken) {
    const validation = await validateInviteToken(inviteToken)
    if (!validation.valid) {
      return { error: { general: ["This invite link is invalid or has expired."] } }
    }
    inviteTokenId = validation.data!.id
    // If token has creator agent, use as referrer
    const tokenRecord = await (prisma as any).inviteToken.findUnique({ where: { token: inviteToken } })
    if (tokenRecord?.createdByAgentId) referrerId = tokenRecord.createdByAgentId
  } else if (referrerCode) {
    const referrer = await prisma.agent.findUnique({ where: { agentCode: referrerCode } })
    if (referrer) referrerId = referrer.id
  }

  // Check if they already applied
  const existing = await (prisma as any).recruitmentRequest.findFirst({
    where: { email, status: "PENDING" },
  })

  if (existing) {
    return { error: { general: ["You already have a pending application."] } }
  }

  // Create the request and mark token as used atomically
  await (prisma as any).$transaction(async (tx: any) => {
    const request = await tx.recruitmentRequest.create({
      data: {
        name,
        email,
        phone,
        location,
        requestedRole,
        referrerId,
        notes,
        inviteTokenId,
      },
    })

    if (inviteToken && inviteTokenId) {
      await tx.inviteToken.update({
        where: { id: inviteTokenId },
        data: { usedAt: new Date() },
      })
    }

    return request
  })

  return { success: true }
}

