                                </Select>
                            </div>
                            <div className="space-y-1.5">
                                <Label htmlFor="brand" className="text-[10px] font-black uppercase text-zinc-400 tracking-widest">Brand</Label>
                                <Input 
                                    id="brand"
                                    value={formData.brand}
